diff --git a/llvm/lib/Transforms/Utils/Local.cpp b/llvm/lib/Transforms/Utils/Local.cpp
index babd7f6b3a05..f5e2c705844b 100644
--- a/llvm/lib/Transforms/Utils/Local.cpp
+++ b/llvm/lib/Transforms/Utils/Local.cpp
@@ -482,13 +482,13 @@ bool llvm::wouldInstructionBeTriviallyDead(const Instruction *I,

     if (II->isLifetimeStartOrEnd()) {
       auto *Arg = II->getArgOperand(1);
-      // If the only uses of the alloca are lifetime intrinsics, then the
-      // intrinsics are dead.
-      return llvm::all_of(Arg->uses(), [](Use &Use) {
-        return isa<LifetimeIntrinsic>(Use.getUser());
-      });
+      // If the value does not have a materialized use list, there are no recorded
+      // uses to inspect. Conservatively consider the intrinsic not trivially dead.
+      if (!Arg->hasUseList())
+        return false;
+      // If the only uses of the alloca are lifetime intrinsics, then the intrinsics are dead.
+      return llvm::all_of(Arg->users(), [](User *U) { return isa<LifetimeIntrinsic>(U); });
     }
-
     // Assumptions are dead if their condition is trivially true.
     if (II->getIntrinsicID() == Intrinsic::assume &&
         isAssumeWithEmptyBundle(cast<AssumeInst>(*II))) {

